import pytest
import requests

def test_delete_already_deleted_team_returns_400_or_404(
    base_url, admin_auth_token, create_team, audit_log_client
):
    team = create_team(name="QA-Team-STC-Double-Delete")
    team_id = team["id"]
    headers = {"Authorization": f"Bearer {admin_auth_token}"}

    first = requests.delete(f"{base_url}/teams/{team_id}", headers=headers, timeout=10)
    assert first.status_code in (200, 201), (
        f"First deletion should succeed, got {first.status_code}"
    )

    second = requests.delete(f"{base_url}/teams/{team_id}", headers=headers, timeout=10)
    assert second.status_code in (400, 404), (
        f"Second deletion should fail with 400 or 404, got {second.status_code}"
    )

    entries = audit_log_client.get_all_entries(entity_id=team_id, action="DELETE")
    assert len(entries) == 1, (
        f"Only one audit record expected, found {len(entries)}"
    )
